import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
function Mainweatherpage() {
    let [cityinput, changeinput] = useState("")
    let [citysession, changecitysession] = useState("")
    function function1(e) {
        changeinput(e.target.value)
    }
    async function apicall() {
        let weatherdata  = await fetch(`https://api.openweathermap.org/data/2.5/weather?q=${cityinput[0].toUpperCase() + cityinput.slice(1)}&appid=d782528f491fa0b8359a25fc07739daa&units=metric`)
        let updatedweather = await weatherdata.json()
        let alldata = {maindata: updatedweather.main, city: updatedweather.name, weathertype: updatedweather.weather[0]}
        changecitysession(alldata[0].city)
        console.log(citysession)
    }
    return<>
        <input value={cityinput} onChange={(e) => function1(e)}/>
        <button onClick={() => apicall()}>Look at the weather</button>
    </>
}
export default Mainweatherpage
